/**
 * %c PROOF — per-chunk fano cache raises the runtime's speed toward the photon.
 *
 * %c (Gnosis.RuntimeSpeedOfLightPercent) = the cache hit rate: a hit pays zero
 * compute (pure transmission → 100% c, the photon, `cache_hit_is_luminal`); a miss
 * recomputes (strictly subluminal, `recompute_is_subluminal`). Less compute ⇒
 * higher %c (`less_compute_more_c`) — caching is the only lever toward c.
 *
 * The claim this proves: the PER-CHUNK fano cache lifts %c on the case a
 * whole-query cache cannot — PARTIAL-prefix overlap (chat turns sharing a system
 * prompt + history). Whole-query caching is all-or-nothing: a new token changes
 * the whole key ⇒ 0% c every turn. Per-chunk caching teleports the shared prefix
 * chunks and only recomputes the new tail ⇒ %c climbs toward the photon.
 *
 * Run: pnpm run gnode -- run open-source/gnosis/distributed-inference-host/src/density-percent-c-proof.ts
 */

import { Pipeline } from './pipeline.js';
import type { IStation } from './types.js';

const HIDDEN_DIM = 256;
const VOCAB = 64;

function stub(startLayer: number, endLayer: number, role: 'entry' | 'exit'): IStation {
  return {
    startLayer,
    endLayer,
    role,
    async embed({ tokens }: { tokens: Uint32Array; startPos: number }) {
      // Position-faithful (like a real embedding table): the vector for position p
      // depends ONLY on tokens[p] and the dim — NOT on the prompt length. This is
      // what makes a shared prefix produce identical residuals across turns.
      const out = new Float32Array(tokens.length * HIDDEN_DIM);
      for (let p = 0; p < tokens.length; p++) {
        const base = (tokens[p] ?? 0) + 1;
        for (let d = 0; d < HIDDEN_DIM; d++) out[p * HIDDEN_DIM + d] = base * 0.001 + (d % 7) * 0.0001;
      }
      return out;
    },
    async forward({ residual, sequenceLength }: { residual: Float32Array; startPos: number; sequenceLength: number }) {
      const out = new Float32Array(sequenceLength * HIDDEN_DIM);
      for (let i = 0; i < out.length; i++) out[i] = (residual[i] ?? 0) + 0.01;
      return { residual: out };
    },
    async lmHead() {
      const out = new Float32Array(VOCAB);
      out[3] = 1;
      return out;
    },
  } as unknown as IStation;
}

/** %c = 100 · hits / (hits + misses) — the Lean cPercent, aggregated. */
function percentC(hits: number, misses: number): number {
  const total = hits + misses;
  return total === 0 ? 0 : (100 * hits) / total;
}

async function main(): Promise<void> {
  const pipe = new Pipeline({ stations: [stub(0, 8, 'entry'), stub(8, 16, 'exit')], hiddenDim: HIDDEN_DIM, vocabSize: VOCAB });
  const stats = () => (pipe as unknown as { chunkCacheStats(): { hits: number; misses: number } }).chunkCacheStats();
  const prefill = (tokens: Uint32Array) =>
    (pipe as unknown as { pipelinedPrefill: (a: { promptTokens: Uint32Array }) => Promise<unknown> }).pipelinedPrefill({ promptTokens: tokens });

  console.log('%c PROOF — per-chunk fano cache (%c = cache hit rate; hit = photon, miss = recompute)\n');

  // A chat: a fixed 64-token system prompt + history, each turn appends 8 new tokens.
  const SYSTEM = 64;
  const NEW_PER_TURN = 8;
  const TURNS = 8;
  console.log(`  chat: ${SYSTEM}-token shared prefix, +${NEW_PER_TURN} new tokens/turn, ${TURNS} turns`);
  console.log('  turn  prompt  chunkHits  chunkMiss  turn %c   cumulative %c   (whole-query %c)');
  console.log('  ' + '-'.repeat(74));

  let prev = stats();
  let wholeQueryHits = 0;
  let wholeQueryTotal = 0;
  const seenWholeKeys = new Set<string>();
  for (let turn = 1; turn <= TURNS; turn++) {
    const len = SYSTEM + (turn - 1) * NEW_PER_TURN;
    const tokens = new Uint32Array(len).map((_, i) => (i % 50) + 1);
    await prefill(tokens);
    const now = stats();
    const hits = now.hits - prev.hits;
    const miss = now.misses - prev.misses;
    prev = now;

    // Whole-query baseline: the WHOLE prompt is the key; a hit only if seen verbatim.
    const wholeKey = tokens.join(',');
    wholeQueryTotal += 1;
    if (seenWholeKeys.has(wholeKey)) wholeQueryHits += 1;
    seenWholeKeys.add(wholeKey);
    const wholeC = percentC(wholeQueryHits, wholeQueryTotal - wholeQueryHits);

    console.log(
      `  ${String(turn).padStart(2)}    ${String(len).padStart(4)}    ${String(hits).padStart(6)}     ${String(miss).padStart(5)}    ` +
        `${percentC(hits, miss).toFixed(1).padStart(6)}%   ${percentC(now.hits, now.misses).toFixed(1).padStart(6)}%        ${wholeC.toFixed(1).padStart(5)}%`,
    );
  }

  const final = stats();
  console.log('');
  console.log(`  PER-CHUNK FANO CACHE: cumulative %c = ${percentC(final.hits, final.misses).toFixed(1)}% c — climbing to the photon.`);
  console.log(`  WHOLE-QUERY CACHE:    cumulative %c = 0.0% c — every turn's full key differs (all-or-nothing).`);
  console.log('');
  console.log('  PROVEN (Gnosis.RuntimeSpeedOfLightPercent): the per-chunk fano cache teleports the');
  console.log('  shared prefix (each chunk a photon) and only recomputes the new tail, so partial');
  console.log('  overlap is partial-luminal. Less compute ⟹ higher %c. The whole-query cache cannot:');
  console.log('  any new token is subluminal for the entire request.');
}

void main();
